svg.script:
(async function() {
  const frame = document.getElementById('main-frame');

  const currentUrl = window.location.href.split('?')[0].split('#')[0];
  const repoBase = currentUrl.substring(0, currentUrl.lastIndexOf('/') + 1);

  async function renderPage(url) {
    try {
      const response = await fetch(url + "?cb=" + Date.now());
      if (!response.ok) throw new Error("Status: " + response.status);

      let html = await response.text();

      const interceptor = `
        <base href="${repoBase}">
        <script>
          document.addEventListener('click', e => {
            const a = e.target.closest('a');
            if (a && a.href.startsWith('${repoBase}') && !a.target) {
              e.preventDefault();
              window.parent.postMessage({type: 'NAV', url: a.href}, '*');
            }
          });
        <\/script>
      `;

      html = html.replace('<head>', '<head>' + interceptor);

      const blob = new Blob([html], { type: 'text/html' });
      const blobUrl = URL.createObjectURL(blob);

      frame.src = blobUrl;
      frame.classList.add('visible');

    } catch (err) {
      console.error("Dominum Loader Error:", err);
      frame.srcdoc = "<body style='background:#0b0a16;color:#e6e6ff;text-align:center;padding-top:20%;font-family:sans-serif;'><h2>Load Failed</h2><p>"+err.message+"</p></body>";
      frame.classList.add('visible');
    }
  }

  window.addEventListener('message', e => {
    if (e.data && e.data.type === 'NAV') renderPage(e.data.url);
  });

  renderPage(repoBase + 'index.html');
})();
